// ============================================================================\n// ENTERPRISE-GRADE ERROR HANDLING SYSTEM\n// ============================================================================\n\n/// \n/// Comprehensive Error Handling System\n/// \n/// Provides enterprise-grade error management with:\n/// - Structured error classification\n/// - Centralized error reporting\n/// - User-friendly error messages\n/// - Debug information for development\n/// - Error recovery strategies\n/// \n/// @author Senior Development Team\n/// @version 2.0.0\n/// @since 1.0.0\n/// \n\nimport 'package:flutter/foundation.dart';\nimport 'package:flutter/material.dart';\nimport 'dart:io';\n\n// ============================================================================\n// ERROR CLASSIFICATION\n// ============================================================================\n\n/// Error severity levels\nenum ErrorSeverity {\n  low,\n  medium,\n  high,\n  critical,\n}\n\n/// Error categories for better handling\nclass ErrorCategory {\n  static const String network = 'network';\n  static const String authentication = 'authentication';\n  static const String database = 'database';\n  static const String validation = 'validation';\n  static const String permission = 'permission';\n  static const String storage = 'storage';\n  static const String configuration = 'configuration';\n  static const String ui = 'ui';\n  static const String unknown = 'unknown';\n}\n\n// ============================================================================\n// CUSTOM ERROR TYPES\n// ============================================================================\n\n/// Base application error class\nabstract class AppError implements Exception {\n  final String message;\n  final String? code;\n  final String category;\n  final ErrorSeverity severity;\n  final dynamic originalError;\n  final StackTrace? stackTrace;\n  final Map<String, dynamic>? context;\n  \n  const AppError({\n    required this.message,\n    this.code,\n    required this.category,\n    this.severity = ErrorSeverity.medium,\n    this.originalError,\n    this.stackTrace,\n    this.context,\n  });\n  \n  /// Get user-friendly error message\n  String get userMessage => _getUserFriendlyMessage();\n  \n  /// Check if error is recoverable\n  bool get isRecoverable => _isRecoverable();\n  \n  /// Get suggested recovery action\n  String? get recoveryAction => _getRecoveryAction();\n  \n  /// Convert to map for logging\n  Map<String, dynamic> toMap() {\n    return {\n      'type': runtimeType.toString(),\n      'message': message,\n      'code': code,\n      'category': category,\n      'severity': severity.toString(),\n      'isRecoverable': isRecoverable,\n      'recoveryAction': recoveryAction,\n      'originalError': originalError?.toString(),\n      'context': context,\n      'timestamp': DateTime.now().toIso8601String(),\n    };\n  }\n  \n  @override\n  String toString() {\n    return 'AppError: $message (Category: $category, Severity: $severity)';\n  }\n  \n  // Abstract methods to be implemented by subclasses\n  String _getUserFriendlyMessage();\n  bool _isRecoverable();\n  String? _getRecoveryAction();\n}\n\n/// Network-related errors\nclass NetworkError extends AppError {\n  const NetworkError({\n    required super.message,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.medium,\n  }) : super(category: ErrorCategory.network);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    if (originalError is SocketException) {\n      return 'No internet connection. Please check your network settings.';\n    } else if (originalError is TimeoutException) {\n      return 'Request timed out. Please try again.';\n    }\n    return 'Network error occurred. Please check your connection and try again.';\n  }\n  \n  @override\n  bool _isRecoverable() => true;\n  \n  @override\n  String? _getRecoveryAction() => 'Check your internet connection and try again.';\n}\n\n/// Authentication-related errors\nclass AuthenticationError extends AppError {\n  const AuthenticationError({\n    required super.message,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.high,\n  }) : super(category: ErrorCategory.authentication);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    switch (code) {\n      case 'user-not-found':\n        return 'User account not found. Please check your credentials.';\n      case 'wrong-password':\n        return 'Incorrect password. Please try again.';\n      case 'email-already-in-use':\n        return 'This email is already registered. Please use a different email.';\n      case 'weak-password':\n        return 'Password is too weak. Please choose a stronger password.';\n      case 'invalid-email':\n        return 'Invalid email address. Please check and try again.';\n      case 'user-disabled':\n        return 'This account has been disabled. Please contact support.';\n      case 'too-many-requests':\n        return 'Too many failed attempts. Please try again later.';\n      case 'session-expired':\n        return 'Your session has expired. Please sign in again.';\n      default:\n        return 'Authentication error occurred. Please try again.';\n    }\n  }\n  \n  @override\n  bool _isRecoverable() => code != 'user-disabled';\n  \n  @override\n  String? _getRecoveryAction() {\n    switch (code) {\n      case 'user-not-found':\n      case 'wrong-password':\n        return 'Check your credentials and try again.';\n      case 'email-already-in-use':\n        return 'Use a different email address or sign in.';\n      case 'weak-password':\n        return 'Choose a stronger password with at least 8 characters.';\n      case 'invalid-email':\n        return 'Enter a valid email address.';\n      case 'too-many-requests':\n        return 'Wait a few minutes before trying again.';\n      case 'session-expired':\n        return 'Sign in again to continue.';\n      default:\n        return 'Try again or contact support if the problem persists.';\n    }\n  }\n}\n\n/// Database-related errors\nclass DatabaseError extends AppError {\n  const DatabaseError({\n    required super.message,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.high,\n  }) : super(category: ErrorCategory.database);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    switch (code) {\n      case 'permission-denied':\n        return 'You don\\'t have permission to access this data.';\n      case 'not-found':\n        return 'The requested data was not found.';\n      case 'already-exists':\n        return 'This data already exists.';\n      case 'resource-exhausted':\n        return 'Server is busy. Please try again later.';\n      case 'unavailable':\n        return 'Service is temporarily unavailable. Please try again later.'\n      case 'deadline-exceeded':\n        return 'Request took too long. Please try again.';\n      default:\n        return 'Database error occurred. Please try again.';\n    }\n  }\n  \n  @override\n  bool _isRecoverable() => code != 'permission-denied';\n  \n  @override\n  String? _getRecoveryAction() {\n    switch (code) {\n      case 'permission-denied':\n        return 'Contact support for access permissions.';\n      case 'not-found':\n        return 'Check if the data exists or refresh the page.';\n      case 'resource-exhausted':\n      case 'unavailable':\n        return 'Wait a moment and try again.';\n      default:\n        return 'Try again or contact support.';\n    }\n  }\n}\n\n/// Validation errors\nclass ValidationError extends AppError {\n  final String? field;\n  \n  const ValidationError({\n    required super.message,\n    this.field,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.low,\n  }) : super(category: ErrorCategory.validation);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    if (field != null) {\n      return 'Invalid $field: $message';\n    }\n    return 'Validation error: $message';\n  }\n  \n  @override\n  bool _isRecoverable() => true;\n  \n  @override\n  String? _getRecoveryAction() {\n    if (field != null) {\n      return 'Please check the $field field and correct the error.';\n    }\n    return 'Please check your input and correct the errors.';\n  }\n}\n\n/// Permission errors\nclass PermissionError extends AppError {\n  final String? permission;\n  \n  const PermissionError({\n    required super.message,\n    this.permission,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.medium,\n  }) : super(category: ErrorCategory.permission);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    if (permission != null) {\n      switch (permission) {\n        case 'location':\n          return 'Location permission is required for this feature.';\n        case 'camera':\n          return 'Camera permission is required to take photos.';\n        case 'storage':\n          return 'Storage permission is required to save files.';\n        case 'notifications':\n          return 'Notification permission is required for alerts.';\n        default:\n          return 'Permission is required for this feature.';\n      }\n    }\n    return 'Permission required to access this feature.';\n  }\n  \n  @override\n  bool _isRecoverable() => true;\n  \n  @override\n  String? _getRecoveryAction() {\n    if (permission != null) {\n      return 'Grant $permission permission in your device settings.';\n    }\n    return 'Grant the required permission in your device settings.';\n  }\n}\n\n/// Configuration errors\nclass ConfigurationError extends AppError {\n  const ConfigurationError({\n    required super.message,\n    super.code,\n    super.originalError,\n    super.stackTrace,\n    super.context,\n    super.severity = ErrorSeverity.critical,\n  }) : super(category: ErrorCategory.configuration);\n  \n  @override\n  String _getUserFriendlyMessage() {\n    return 'Application configuration error. Please restart the app.';\n  }\n  \n  @override\n  bool _isRecoverable() => false;\n  \n  @override\n  String? _getRecoveryAction() => 'Restart the application or contact support.';\n}\n\n// ============================================================================\n// ERROR HANDLER\n// ============================================================================\n\n/// Global error handler for centralized error management\nclass ErrorHandler {\n  static final ErrorHandler _instance = ErrorHandler._internal();\n  factory ErrorHandler() => _instance;\n  ErrorHandler._internal();\n  \n  final List<AppError> _errorHistory = [];\n  final List<Function(AppError)> _errorListeners = [];\n  \n  /// Handle an error with appropriate logging and user notification\n  void handleError(\n    dynamic error, {\n    StackTrace? stackTrace,\n    Map<String, dynamic>? context,\n    String? fallbackMessage,\n  }) {\n    final appError = _convertToAppError(error, stackTrace, context);\n    \n    // Log the error\n    _logError(appError);\n    \n    // Add to history\n    _errorHistory.add(appError);\n    \n    // Keep only last 100 errors\n    if (_errorHistory.length > 100) {\n      _errorHistory.removeAt(0);\n    }\n    \n    // Notify listeners\n    for (final listener in _errorListeners) {\n      try {\n        listener(appError);\n      } catch (e) {\n        debugPrint('Error in error listener: $e');\n      }\n    }\n    \n    // Show user notification for high severity errors\n    if (appError.severity.index >= ErrorSeverity.high.index) {\n      _showUserNotification(appError);\n    }\n  }\n  \n  /// Convert any error to AppError\n  AppError _convertToAppError(\n    dynamic error,\n    StackTrace? stackTrace,\n    Map<String, dynamic>? context,\n  ) {\n    if (error is AppError) {\n      return error;\n    }\n    \n    // Convert common error types\n    if (error is SocketException || error is TimeoutException) {\n      return NetworkError(\n        message: error.toString(),\n        originalError: error,\n        stackTrace: stackTrace,\n        context: context,\n      );\n    }\n    \n    if (error is FormatException) {\n      return ValidationError(\n        message: error.message,\n        originalError: error,\n        stackTrace: stackTrace,\n        context: context,\n      );\n    }\n    \n    if (error is StateError) {\n      return ValidationError(\n        message: 'Invalid state: ${error.message}',\n        originalError: error,\n        stackTrace: stackTrace,\n        context: context,\n      );\n    }\n    \n    // Default to generic error\n    return AppError(\n      message: error.toString(),\n      category: ErrorCategory.unknown,\n      originalError: error,\n      stackTrace: stackTrace,\n      context: context,\n    ) {\n      @override\n      String _getUserFriendlyMessage() => 'An unexpected error occurred. Please try again.';\n      \n      @override\n      bool _isRecoverable() => true;\n      \n      @override\n      String? _getRecoveryAction() => 'Try again or restart the app.';\n    };\n  }\n  \n  /// Log error for debugging\n  void _logError(AppError error) {\n    if (kDebugMode) {\n      debugPrint('=== ERROR LOG ===');\n      debugPrint('Type: ${error.runtimeType}');\n      debugPrint('Message: ${error.message}');\n      debugPrint('Category: ${error.category}');\n      debugPrint('Severity: ${error.severity}');\n      debugPrint('User Message: ${error.userMessage}');\n      debugPrint('Recoverable: ${error.isRecoverable}');\n      debugPrint('Recovery Action: ${error.recoveryAction}');\n      \n      if (error.originalError != null) {\n        debugPrint('Original Error: ${error.originalError}');\n      }\n      \n      if (error.context != null) {\n        debugPrint('Context: ${error.context}');\n      }\n      \n      if (error.stackTrace != null) {\n        debugPrint('Stack Trace: ${error.stackTrace}');\n      }\n      \n      debugPrint('================');\n    }\n  }\n  \n  /// Show user notification for high severity errors\n  void _showUserNotification(AppError error) {\n    // This would typically show a snackbar, dialog, or toast\n    // Implementation depends on the UI framework being used\n    if (kDebugMode) {\n      debugPrint('USER NOTIFICATION: ${error.userMessage}');\n    }\n  }\n  \n  /// Add error listener\n  void addErrorListener(Function(AppError) listener) {\n    _errorListeners.add(listener);\n  }\n  \n  /// Remove error listener\n  void removeErrorListener(Function(AppError) listener) {\n    _errorListeners.remove(listener);\n  }\n  \n  /// Get error history\n  List<AppError> getErrorHistory() => List.unmodifiable(_errorHistory);\n  \n  /// Clear error history\n  void clearErrorHistory() {\n    _errorHistory.clear();\n  }\n  \n  /// Get error statistics\n  Map<String, dynamic> getErrorStatistics() {\n    final stats = <String, int>{};\n    final severityStats = <ErrorSeverity, int>{};\n    \n    for (final error in _errorHistory) {\n      stats[error.category] = (stats[error.category] ?? 0) + 1;\n      severityStats[error.severity] = (severityStats[error.severity] ?? 0) + 1;\n    }\n    \n    return {\n      'totalErrors': _errorHistory.length,\n      'byCategory': stats,\n      'bySeverity': severityStats.map(\n        (key, value) => MapEntry(key.toString(), value),\n      ),\n    };\n  }\n}\n\n// ============================================================================\n// ERROR BOUNDARY WIDGET\n// ============================================================================\n\n/// Widget that catches and handles errors in its child widget tree\nclass ErrorBoundary extends StatefulWidget {\n  final Widget child;\n  final Widget Function(AppError error)? errorBuilder;\n  final void Function(AppError error)? onError;\n  \n  const ErrorBoundary({\n    super.key,\n    required this.child,\n    this.errorBuilder,\n    this.onError,\n  });\n  \n  @override\n  State<ErrorBoundary> createState() => _ErrorBoundaryState();\n}\n\nclass _ErrorBoundaryState extends State<ErrorBoundary> {\n  AppError? _error;\n  \n  @override\n  void initState() {\n    super.initState();\n    ErrorHandler().addErrorListener(_handleError);\n  }\n  \n  @override\n  void dispose() {\n    ErrorHandler().removeErrorListener(_handleError);\n    super.dispose();\n  }\n  \n  void _handleError(AppError error) {\n    if (mounted) {\n      setState(() {\n        _error = error;\n      });\n      \n      widget.onError?.call(error);\n    }\n  }\n  \n  @override\n  Widget build(BuildContext context) {\n    if (_error != null) {\n      if (widget.errorBuilder != null) {\n        return widget.errorBuilder!(_error!);\n      }\n      \n      return _DefaultErrorWidget(error: _error!);\n    }\n    \n    return widget.child;\n  }\n}\n\n/// Default error widget for displaying errors to users\nclass _DefaultErrorWidget extends StatelessWidget {\n  final AppError error;\n  \n  const _DefaultErrorWidget({required this.error});\n  \n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      backgroundColor: Theme.of(context).colorScheme.errorContainer,\n      body: Center(\n        child: Padding(\n          padding: const EdgeInsets.all(24.0),\n          child: Column(\n            mainAxisAlignment: MainAxisAlignment.center,\n            children: [\n              Icon(\n                Icons.error_outline,\n                size: 64,\n                color: Theme.of(context).colorScheme.error,\n              ),\n              const SizedBox(height: 16),\n              Text(\n                'Something went wrong',\n                style: Theme.of(context).textTheme.headlineSmall,\n                textAlign: TextAlign.center,\n              ),\n              const SizedBox(height: 8),\n              Text(\n                error.userMessage,\n                style: Theme.of(context).textTheme.bodyMedium,\n                textAlign: TextAlign.center,\n              ),\n              if (error.recoveryAction != null) ...[\n                const SizedBox(height: 16),\n                Text(\n                  error.recoveryAction!,\n                  style: Theme.of(context).textTheme.bodySmall,\n                  textAlign: TextAlign.center,\n                ),\n              ],\n              if (error.isRecoverable) ...[\n                const SizedBox(height: 24),\n                ElevatedButton(\n                  onPressed: () {\n                    // Try to recover by reloading or retrying\n                    // This would be implemented based on the specific error type\n                  },\n                  child: const Text('Try Again'),\n                ),\n              ],\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n}\n\n// ============================================================================\n// UTILITY FUNCTIONS\n// ============================================================================\n\n/// Safe execute function that catches and handles errors\nFuture<T?> safeExecute<T>(\n  Future<T> Function() operation, {\n  T? fallback,\n  Map<String, dynamic>? context,\n  String? operationName,\n}) async {\n  try {\n    return await operation();\n  } catch (error, stackTrace) {\n    ErrorHandler().handleError(\n      error,\n      stackTrace: stackTrace,\n      context: {\n        'operation': operationName ?? 'unknown',\n        ...?context,\n      },\n    );\n    return fallback;\n  }\n}\n\n/// Safe execute function for synchronous operations\nT? safeExecuteSync<T>(\n  T Function() operation, {\n  T? fallback,\n  Map<String, dynamic>? context,\n  String? operationName,\n}) {\n  try {\n    return operation();\n  } catch (error, stackTrace) {\n    ErrorHandler().handleError(\n      error,\n      stackTrace: stackTrace,\n      context: {\n        'operation': operationName ?? 'unknown',\n        ...?context,\n      },\n    );\n    return fallback;\n  }\n}\n\n/// Extension for adding error handling to Futures\nextension SafeFuture<T> on Future<T> {\n  Future<T?> safe({\n    T? fallback,\n    Map<String, dynamic>? context,\n    String? operationName,\n  }) {\n    return safeExecute(\n      () => this,\n      fallback: fallback,\n      context: context,\n      operationName: operationName,\n    );\n  }\n}
